using Microsoft.AspNetCore.Authorization;
using Microsoft.EntityFrameworkCore;
using ShipmentTracker.Data;

namespace ShipmentTracker.Endpoints;

public static class ShipmentEndpoints
{
    public static void MapShipmentEndpoints(this WebApplication app)
    {
        var group = app.MapGroup("/api/shipments").RequireAuthorization();

        // Get all shipments (dispatchers)
        group.MapGet("/", [Authorize(Roles = "Dispatcher")] async (ApplicationDbContext db) =>
        {
            var shipments = await db.Shipments
                .OrderByDescending(s => s.ShippedDate)
                .ToListAsync();

            return Results.Ok(shipments.Select(MapToDto));
        });

        // Get shipment by tracking number (customers)
        group.MapGet("/track/{trackingNumber}", async (string trackingNumber, ApplicationDbContext db, HttpContext http) =>
        {
            var shipment = await db.Shipments
                .FirstOrDefaultAsync(s => s.TrackingNumber == trackingNumber);

            if (shipment is null)
                return Results.NotFound();

            var userEmail = http.User.Identity?.Name;
            var isDispatcher = http.User.IsInRole("Dispatcher");

            if (!isDispatcher && !string.Equals(shipment.CustomerEmail, userEmail, StringComparison.OrdinalIgnoreCase))
                return Results.Forbid();

            return Results.Ok(MapToDto(shipment));
        });

        // Get shipments for the current customer
        group.MapGet("/my", async (ApplicationDbContext db, HttpContext http) =>
        {
            var userEmail = http.User.Identity?.Name ?? string.Empty;

            var shipments = await db.Shipments
                .Where(s => s.CustomerEmail == userEmail)
                .OrderByDescending(s => s.ShippedDate)
                .ToListAsync();

            return Results.Ok(shipments.Select(MapToDto));
        });

        // Create a shipment (dispatchers)
        group.MapPost("/", [Authorize(Roles = "Dispatcher")] async (CreateShipmentRequest request, ApplicationDbContext db) =>
        {
            var shipment = new Shipment
            {
                TrackingNumber = GenerateTrackingNumber(),
                Origin = request.Origin,
                Destination = request.Destination,
                Status = ShipmentStatus.Pending,
                ShippedDate = DateTime.UtcNow,
                EstimatedDelivery = request.EstimatedDelivery,
                CustomerEmail = request.CustomerEmail,
                Description = request.Description
            };

            db.Shipments.Add(shipment);
            await db.SaveChangesAsync();

            return Results.Created($"/api/shipments/track/{shipment.TrackingNumber}", MapToDto(shipment));
        });

        // Update shipment status (dispatchers)
        group.MapPut("/{id:int}/status", [Authorize(Roles = "Dispatcher")] async (int id, UpdateStatusRequest request, ApplicationDbContext db) =>
        {
            var shipment = await db.Shipments.FindAsync(id);
            if (shipment is null)
                return Results.NotFound();

            shipment.Status = request.NewStatus;
            if (request.EstimatedDelivery.HasValue)
                shipment.EstimatedDelivery = request.EstimatedDelivery.Value;

            await db.SaveChangesAsync();
            return Results.Ok(MapToDto(shipment));
        });
    }

    private static object MapToDto(Shipment s) => new
    {
        s.Id,
        s.TrackingNumber,
        s.Origin,
        s.Destination,
        Status = s.Status.ToString(),
        s.ShippedDate,
        s.EstimatedDelivery,
        s.CustomerEmail,
        s.Description
    };

    private static string GenerateTrackingNumber()
    {
        return $"SHP-{DateTime.UtcNow:yyyyMMdd}-{Random.Shared.Next(100000, 999999)}";
    }
}

public record CreateShipmentRequest(
    string Origin,
    string Destination,
    DateTime EstimatedDelivery,
    string CustomerEmail,
    string Description);

public record UpdateStatusRequest(
    ShipmentStatus NewStatus,
    DateTime? EstimatedDelivery);

