@page "/track"
@using Microsoft.AspNetCore.Authorization
@using ShipmentTracker.Client.Models
@attribute [Authorize]
@rendermode InteractiveWebAssembly
@inject HttpClient Http

<PageTitle>Track Shipment</PageTitle>

<h3>Track Your Shipment</h3>

<div class="row mb-4">
    <div class="col-md-6">
        <div class="input-group">
            <input type="text" class="form-control" placeholder="Enter tracking number (e.g., SHP-20260501-100001)"
                   @bind="trackingNumber" @onkeyup="HandleKeyPress" />
            <button class="btn btn-primary" @onclick="TrackShipment" disabled="@isLoading">
                @if (isLoading)
                {
                    <span class="spinner-border spinner-border-sm" role="status"></span>
                }
                else
                {
                    <span>Track</span>
                }
            </button>
        </div>
    </div>
</div>

@if (errorMessage is not null)
{
    <div class="alert alert-warning">@errorMessage</div>
}

@if (trackedShipment is not null)
{
    <div class="card mb-4">
        <div class="card-header">
            <strong>@trackedShipment.TrackingNumber</strong>
            <span class="badge @GetStatusBadgeClass(trackedShipment.Status) ms-2">@trackedShipment.Status</span>
        </div>
        <div class="card-body">
            <div class="row">
                <div class="col-md-6">
                    <dl>
                        <dt>From</dt>
                        <dd>@trackedShipment.Origin</dd>
                        <dt>To</dt>
                        <dd>@trackedShipment.Destination</dd>
                        <dt>Description</dt>
                        <dd>@trackedShipment.Description</dd>
                    </dl>
                </div>
                <div class="col-md-6">
                    <dl>
                        <dt>Shipped Date</dt>
                        <dd>@trackedShipment.ShippedDate.ToString("MMMM dd, yyyy")</dd>
                        <dt>Estimated Delivery</dt>
                        <dd class="@(trackedShipment.EstimatedDelivery < DateTime.UtcNow && trackedShipment.Status != ShipmentStatus.Delivered ? "text-danger fw-bold" : "")">
                            @trackedShipment.EstimatedDelivery.ToString("MMMM dd, yyyy")
                            @if (trackedShipment.Status != ShipmentStatus.Delivered)
                            {
                                var daysLeft = (trackedShipment.EstimatedDelivery - DateTime.UtcNow).Days;
                                <span class="text-muted">
                                    (@(daysLeft > 0 ? $"in {daysLeft} days" : daysLeft == 0 ? "today" : $"{Math.Abs(daysLeft)} days overdue"))
                                </span>
                            }
                        </dd>
                    </dl>
                </div>
            </div>

            <!-- Progress indicator -->
            <div class="mt-3">
                <h6>Shipment Progress</h6>
                <div class="progress" style="height: 25px;">
                    <div class="progress-bar @GetProgressBarClass(trackedShipment.Status)"
                         role="progressbar"
                         style="width: @GetProgressPercentage(trackedShipment.Status)%">
                        @trackedShipment.Status
                    </div>
                </div>
            </div>
        </div>
    </div>
}

<hr />

<h4>My Shipments</h4>

@if (myShipments is null)
{
    <p><em>Loading your shipments...</em></p>
}
else if (!myShipments.Any())
{
    <p>You have no shipments on record.</p>
}
else
{
    <div class="row">
        @foreach (var shipment in myShipments)
        {
            <div class="col-md-6 mb-3">
                <div class="card @(shipment.Status == ShipmentStatus.Delayed ? "border-danger" : "")">
                    <div class="card-body">
                        <h6 class="card-title">
                            <code>@shipment.TrackingNumber</code>
                            <span class="badge @GetStatusBadgeClass(shipment.Status) ms-1">@shipment.Status</span>
                        </h6>
                        <p class="card-text mb-1">
                            <strong>@shipment.Origin</strong> → <strong>@shipment.Destination</strong>
                        </p>
                        <p class="card-text text-muted small mb-1">@shipment.Description</p>
                        <p class="card-text">
                            <small>Est. Delivery: @shipment.EstimatedDelivery.ToString("MMM dd, yyyy")</small>
                        </p>
                        <button class="btn btn-sm btn-outline-primary"
                                @onclick="() => TrackSpecific(shipment.TrackingNumber)">
                            View Details
                        </button>
                    </div>
                </div>
            </div>
        }
    </div>
}

@code {
    private string trackingNumber = string.Empty;
    private ShipmentDto? trackedShipment;
    private List<ShipmentDto>? myShipments;
    private string? errorMessage;
    private bool isLoading;

    protected override async Task OnInitializedAsync()
    {
        myShipments = await Http.GetFromJsonAsync<List<ShipmentDto>>("/api/shipments/my");
    }

    private async Task HandleKeyPress(KeyboardEventArgs e)
    {
        if (e.Key == "Enter")
            await TrackShipment();
    }

    private async Task TrackShipment()
    {
        if (string.IsNullOrWhiteSpace(trackingNumber))
            return;

        isLoading = true;
        errorMessage = null;
        trackedShipment = null;

        try
        {
            var response = await Http.GetAsync($"/api/shipments/track/{trackingNumber.Trim()}");
            if (response.IsSuccessStatusCode)
            {
                trackedShipment = await response.Content.ReadFromJsonAsync<ShipmentDto>();
            }
            else if (response.StatusCode == System.Net.HttpStatusCode.NotFound)
            {
                errorMessage = "No shipment found with that tracking number.";
            }
            else
            {
                errorMessage = "Unable to retrieve shipment information.";
            }
        }
        catch
        {
            errorMessage = "An error occurred. Please try again.";
        }
        finally
        {
